     1→package api
     2→
     3→import (
     4→	"context"
     5→	"net/http"
     6→	"strings"
     7→
     8→	"github.com/sentioxyz/changelogue/internal/models"
     9→)
    10→
    11→// SubscriptionsStore defines the persistence operations for subscriptions.
    12→type SubscriptionsStore interface {
    13→	ListSubscriptions(ctx context.Context, page, perPage int) ([]models.Subscription, int, error)
    14→	CreateSubscription(ctx context.Context, sub *models.Subscription) error
    15→	CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error)
    16→	GetSubscription(ctx context.Context, id string) (*models.Subscription, error)
    17→	UpdateSubscription(ctx context.Context, id string, sub *models.Subscription) error
    18→	DeleteSubscription(ctx context.Context, id string) error
    19→	DeleteSubscriptionBatch(ctx context.Context, ids []string) error
    20→}
    21→
    22→// SubscriptionsHandler implements HTTP handlers for the /subscriptions resource.
    23→type SubscriptionsHandler struct {
    24→	store SubscriptionsStore
    25→}
    26→
    27→// NewSubscriptionsHandler returns a new SubscriptionsHandler.
    28→func NewSubscriptionsHandler(store SubscriptionsStore) *SubscriptionsHandler {
    29→	return &SubscriptionsHandler{store: store}
    30→}
    31→
    32→// List handles GET /subscriptions — returns a paginated list of subscriptions.
    33→func (h *SubscriptionsHandler) List(w http.ResponseWriter, r *http.Request) {
    34→	page, perPage := ParsePagination(r)
    35→	subs, total, err := h.store.ListSubscriptions(r.Context(), page, perPage)
    36→	if err != nil {
    37→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list subscriptions")
    38→		return
    39→	}
    40→	if subs == nil {
    41→		subs = []models.Subscription{}
    42→	}
    43→	RespondList(w, r, http.StatusOK, subs, page, perPage, total)
    44→}
    45→
    46→// Create handles POST /subscriptions — creates a new subscription.
    47→func (h *SubscriptionsHandler) Create(w http.ResponseWriter, r *http.Request) {
    48→	var sub models.Subscription
    49→	if err := DecodeJSON(r, &sub); err != nil {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    51→		return
    52→	}
    53→	sub.Type = strings.TrimSpace(sub.Type)
    54→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
    55→	// Validate type is source_release or semantic_release.
    56→	if sub.Type != "source_release" && sub.Type != "semantic_release" {
    57→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
    58→		return
    59→	}
    60→	if sub.ChannelID == "" {
    61→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
    62→		return
    63→	}
    64→	// Validate that the corresponding ID is set for the type.
    65→	if sub.Type == "source_release" && (sub.SourceID == nil || *sub.SourceID == "") {
    66→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_id is required when type is 'source_release'")
    67→		return
    68→	}
    69→	if sub.Type == "semantic_release" && (sub.ProjectID == nil || *sub.ProjectID == "") {
    70→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required when type is 'semantic_release'")
    71→		return
    72→	}
    73→	if err := h.store.CreateSubscription(r.Context(), &sub); err != nil {
    74→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscription")
    75→		return
    76→	}
    77→	RespondJSON(w, r, http.StatusCreated, sub)
    78→}
    79→
    80→// Get handles GET /subscriptions/{id} — returns a single subscription.
    81→func (h *SubscriptionsHandler) Get(w http.ResponseWriter, r *http.Request) {
    82→	id := r.PathValue("id")
    83→	if id == "" {
    84→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
    85→		return
    86→	}
    87→	sub, err := h.store.GetSubscription(r.Context(), id)
    88→	if err != nil {
    89→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
    90→		return
    91→	}
    92→	RespondJSON(w, r, http.StatusOK, sub)
    93→}
    94→
    95→// Update handles PUT /subscriptions/{id} — updates an existing subscription.
    96→func (h *SubscriptionsHandler) Update(w http.ResponseWriter, r *http.Request) {
    97→	id := r.PathValue("id")
    98→	if id == "" {
    99→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
   100→		return
   101→	}
   102→	var sub models.Subscription
   103→	if err := DecodeJSON(r, &sub); err != nil {
   104→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   105→		return
   106→	}
   107→	sub.Type = strings.TrimSpace(sub.Type)
   108→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
   109→	if sub.Type != "source_release" && sub.Type != "semantic_release" {
   110→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
   111→		return
   112→	}
   113→	if sub.ChannelID == "" {
   114→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
   115→		return
   116→	}
   117→	if sub.Type == "source_release" && (sub.SourceID == nil || *sub.SourceID == "") {
   118→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_id is required when type is 'source_release'")
   119→		return
   120→	}
   121→	if sub.Type == "semantic_release" && (sub.ProjectID == nil || *sub.ProjectID == "") {
   122→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required when type is 'semantic_release'")
   123→		return
   124→	}
   125→	if err := h.store.UpdateSubscription(r.Context(), id, &sub); err != nil {
   126→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
   127→		return
   128→	}
   129→	sub.ID = id
   130→	RespondJSON(w, r, http.StatusOK, sub)
   131→}
   132→
   133→// Delete handles DELETE /subscriptions/{id} — deletes a subscription.
   134→func (h *SubscriptionsHandler) Delete(w http.ResponseWriter, r *http.Request) {
   135→	id := r.PathValue("id")
   136→	if id == "" {
   137→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
   138→		return
   139→	}
   140→	if err := h.store.DeleteSubscription(r.Context(), id); err != nil {
   141→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
   142→		return
   143→	}
   144→	w.WriteHeader(http.StatusNoContent)
   145→}
   146→
   147→// BatchSubscriptionInput is the request body for POST /subscriptions/batch.
   148→type BatchSubscriptionInput struct {
   149→	ChannelID     string   `json:"channel_id"`
   150→	Type          string   `json:"type"`
   151→	ProjectIDs    []string `json:"project_ids"`
   152→	SourceIDs     []string `json:"source_ids"`
   153→	VersionFilter string   `json:"version_filter,omitempty"`
   154→}
   155→
   156→// BatchCreate handles POST /subscriptions/batch — creates multiple subscriptions at once.
   157→func (h *SubscriptionsHandler) BatchCreate(w http.ResponseWriter, r *http.Request) {
   158→	var input BatchSubscriptionInput
   159→	if err := DecodeJSON(r, &input); err != nil {
   160→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   161→		return
   162→	}
   163→	input.Type = strings.TrimSpace(input.Type)
   164→	input.ChannelID = strings.TrimSpace(input.ChannelID)
   165→	if input.Type != "source_release" && input.Type != "semantic_release" {
   166→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
   167→		return
   168→	}
   169→	if input.ChannelID == "" {
   170→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
   171→		return
   172→	}
   173→
   174→	var subs []models.Subscription
   175→	if input.Type == "semantic_release" {
   176→		if len(input.ProjectIDs) == 0 {
   177→			RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_ids must not be empty when type is 'semantic_release'")
   178→			return
   179→		}
   180→		for _, pid := range input.ProjectIDs {
   181→			id := pid
   182→			subs = append(subs, models.Subscription{
   183→				ChannelID:     input.ChannelID,
   184→				Type:          input.Type,
   185→				ProjectID:     &id,
   186→				VersionFilter: input.VersionFilter,
   187→			})
   188→		}
   189→	} else {
   190→		if len(input.SourceIDs) == 0 {
   191→			RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_ids must not be empty when type is 'source_release'")
   192→			return
   193→		}
   194→		for _, sid := range input.SourceIDs {
   195→			id := sid
   196→			subs = append(subs, models.Subscription{
   197→				ChannelID:     input.ChannelID,
   198→				Type:          input.Type,
   199→				SourceID:      &id,
   200→				VersionFilter: input.VersionFilter,
   201→			})
   202→		}
   203→	}
   204→
   205→	created, err := h.store.CreateSubscriptionBatch(r.Context(), subs)
   206→	if err != nil {
   207→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscriptions")
   208→		return
   209→	}
   210→	RespondJSON(w, r, http.StatusCreated, created)
   211→}
   212→
   213→// BatchDeleteSubscriptionInput is the request body for DELETE /subscriptions/batch.
   214→type BatchDeleteSubscriptionInput struct {
   215→	IDs []string `json:"ids"`
   216→}
   217→
   218→// BatchDelete handles DELETE /subscriptions/batch — deletes multiple subscriptions at once.
   219→func (h *SubscriptionsHandler) BatchDelete(w http.ResponseWriter, r *http.Request) {
   220→	var input BatchDeleteSubscriptionInput
   221→	if err := DecodeJSON(r, &input); err != nil {
   222→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   223→		return
   224→	}
   225→	if len(input.IDs) == 0 {
   226→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "ids must not be empty")
   227→		return
   228→	}
   229→	if err := h.store.DeleteSubscriptionBatch(r.Context(), input.IDs); err != nil {
   230→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to delete subscriptions")
   231→		return
   232→	}
   233→	w.WriteHeader(http.StatusNoContent)
   234→}
