     1→"use client";
     2→
     3→import { useState, useMemo } from "react";
     4→import { useRouter } from "next/navigation";
     5→import useSWR from "swr";
     6→import { projects as projectsApi, channels as channelsApi, sources as sourcesApi } from "@/lib/api/client";
     7→import { Button } from "@/components/ui/button";
     8→import { Input } from "@/components/ui/input";
     9→import { Label } from "@/components/ui/label";
    10→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
    11→import { Checkbox } from "@/components/ui/checkbox";
    12→import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
    13→import type { Subscription, SubscriptionInput, BatchSubscriptionInput, Source } from "@/lib/api/types";
    14→
    15→interface SubscriptionFormProps {
    16→  initial?: Subscription;
    17→  onSubmit: (input: SubscriptionInput) => Promise<void>;
    18→  onBatchSubmit?: (input: BatchSubscriptionInput) => Promise<void>;
    19→  title: string;
    20→  onSuccess?: () => void;
    21→  onCancel?: () => void;
    22→}
    23→
    24→export function SubscriptionForm({ initial, onSubmit, onBatchSubmit, title, onSuccess, onCancel }: SubscriptionFormProps) {
    25→  const router = useRouter();
    26→  const isEditing = !!initial;
    27→  const [saving, setSaving] = useState(false);
    28→  const [error, setError] = useState("");
    29→  const [type, setType] = useState<"source_release" | "semantic_release">(initial?.type ?? "semantic_release");
    30→  const [channelId, setChannelId] = useState(initial?.channel_id ?? "");
    31→  // Single-select state (edit mode)
    32→  const [projectId, setProjectId] = useState(initial?.project_id ?? "");
    33→  const [sourceId, setSourceId] = useState(initial?.source_id ?? "");
    34→  // Multi-select state (create mode)
    35→  const [selectedProjectIds, setSelectedProjectIds] = useState<string[]>([]);
    36→  const [selectedSourceIds, setSelectedSourceIds] = useState<string[]>([]);
    37→  const [versionFilter, setVersionFilter] = useState(initial?.version_filter ?? "");
    38→
    39→  const { data: projectsData } = useSWR("projects-for-sub", () => projectsApi.list(1, 100));
    40→  const { data: channelsData } = useSWR("channels-for-sub", () => channelsApi.list());
    41→
    42→  // Edit mode: fetch sources for the selected project
    43→  const { data: sourcesData } = useSWR(
    44→    type === "source_release" && isEditing && projectId
    45→      ? `sources-for-sub-${projectId}`
    46→      : null,
    47→    () => sourcesApi.listByProject(projectId)
    48→  );
    49→
    50→  // Create mode (source type): fetch sources for ALL projects
    51→  const projectIds = projectsData?.data.map((p) => p.id) ?? [];
    52→  const { data: allSourcesData } = useSWR(
    53→    type === "source_release" && !isEditing && projectIds.length > 0
    54→      ? `all-sources-for-sub-${projectIds.join(",")}`
    55→      : null,
    56→    async () => {
    57→      const results = await Promise.all(
    58→        projectIds.map((pid) => sourcesApi.listByProject(pid).catch(() => ({ data: [] as Source[] })))
    59→      );
    60→      return results.flatMap((r) => r.data);
    61→    }
    62→  );
    63→
    64→  // Group all sources by project for display
    65→  const sourcesByProject = useMemo(() => {
    66→    if (!allSourcesData || !projectsData?.data) return [];
    67→    const projectMap = new Map(projectsData.data.map((p) => [p.id, p.name]));
    68→    const groups = new Map<string, { projectName: string; sources: Source[] }>();
    69→    for (const s of allSourcesData) {
    70→      const name = projectMap.get(s.project_id) ?? s.project_id;
    71→      if (!groups.has(s.project_id)) {
    72→        groups.set(s.project_id, { projectName: name, sources: [] });
    73→      }
    74→      groups.get(s.project_id)!.sources.push(s);
    75→    }
    76→    return Array.from(groups.values());
    77→  }, [allSourcesData, projectsData]);
    78→
    79→  const toggleProjectId = (id: string) => {
    80→    setSelectedProjectIds((prev) =>
    81→      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    82→    );
    83→  };
    84→
    85→  const toggleSourceId = (id: string) => {
    86→    setSelectedSourceIds((prev) =>
    87→      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]
    88→    );
    89→  };
    90→
    91→  const allProjectIds = projectsData?.data.map((p) => p.id) ?? [];
    92→  const allSourceIds = allSourcesData?.map((s) => s.id) ?? [];
    93→
    94→  const toggleAllProjects = () => {
    95→    if (selectedProjectIds.length === allProjectIds.length) {
    96→      setSelectedProjectIds([]);
    97→    } else {
    98→      setSelectedProjectIds([...allProjectIds]);
    99→    }
   100→  };
   101→
   102→  const toggleAllSources = () => {
   103→    if (selectedSourceIds.length === allSourceIds.length) {
   104→      setSelectedSourceIds([]);
   105→    } else {
   106→      setSelectedSourceIds([...allSourceIds]);
   107→    }
   108→  };
   109→
   110→  const handleSubmit = async (e: React.FormEvent) => {
   111→    e.preventDefault();
   112→    setError("");
   113→    setSaving(true);
   114→    try {
   115→      if (isEditing) {
   116→        await onSubmit({
   117→          channel_id: channelId,
   118→          type,
   119→          source_id: type === "source_release" ? sourceId : undefined,
   120→          project_id: type === "semantic_release" ? projectId : undefined,
   121→          version_filter: versionFilter || undefined,
   122→        });
   123→      } else if (onBatchSubmit) {
   124→        await onBatchSubmit({
   125→          channel_id: channelId,
   126→          type,
   127→          project_ids: type === "semantic_release" ? selectedProjectIds : undefined,
   128→          source_ids: type === "source_release" ? selectedSourceIds : undefined,
   129→          version_filter: versionFilter || undefined,
   130→        });
   131→      }
   132→      if (onSuccess) {
   133→        onSuccess();
   134→      } else {
   135→        router.push("/subscriptions");
   136→      }
   137→    } catch (err: unknown) {
   138→      setError(err instanceof Error ? err.message : "Failed to save");
   139→    } finally {
   140→      setSaving(false);
   141→    }
   142→  };
   143→
   144→  const formContent = (
   145→    <form onSubmit={handleSubmit} className="space-y-4">
   146→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
   147→      <div className="space-y-2">
   148→        <Label>Subscription Type</Label>
   149→        <Select value={type} onValueChange={(v) => { setType(v as "source_release" | "semantic_release"); setSelectedProjectIds([]); setSelectedSourceIds([]); }}>
   150→          <SelectTrigger><SelectValue /></SelectTrigger>
   151→          <SelectContent>
   152→            <SelectItem value="semantic_release">Semantic Release</SelectItem>
   153→            <SelectItem value="source_release">Source Release</SelectItem>
   154→          </SelectContent>
   155→        </Select>
   156→      </div>
   157→
   158→      {/* PROJECT SELECTION */}
   159→      {type === "semantic_release" && isEditing && (
   160→        <div className="space-y-2">
   161→          <Label>Project</Label>
   162→          <Select value={projectId} onValueChange={setProjectId} required>
   163→            <SelectTrigger><SelectValue placeholder="Select project" /></SelectTrigger>
   164→            <SelectContent>
   165→              {projectsData?.data.map((p) => (
   166→                <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
   167→              ))}
   168→            </SelectContent>
   169→          </Select>
   170→        </div>
   171→      )}
   172→      {type === "semantic_release" && !isEditing && (
   173→        <div className="space-y-2">
   174→          <div className="flex items-center justify-between">
   175→            <Label>Projects</Label>
   176→            <button
   177→              type="button"
   178→              onClick={toggleAllProjects}
   179→              className="text-xs text-blue-600 hover:text-blue-800"
   180→            >
   181→              {selectedProjectIds.length === allProjectIds.length ? "Deselect all" : "Select all"}
   182→            </button>
   183→          </div>
   184→          <div className="max-h-48 overflow-y-auto rounded-md border border-input p-2 space-y-1">
   185→            {projectsData?.data.map((p) => (
   186→              <label key={p.id} className="flex items-center gap-2 rounded px-2 py-1.5 hover:bg-accent cursor-pointer">
   187→                <Checkbox
   188→                  checked={selectedProjectIds.includes(p.id)}
   189→                  onCheckedChange={() => toggleProjectId(p.id)}
   190→                />
   191→                <span className="text-sm">{p.name}</span>
   192→              </label>
   193→            ))}
   194→            {(!projectsData?.data || projectsData.data.length === 0) && (
   195→              <p className="text-sm text-muted-foreground px-2 py-1">No projects found</p>
   196→            )}
   197→          </div>
   198→          {selectedProjectIds.length > 0 && (
   199→            <p className="text-xs text-muted-foreground">{selectedProjectIds.length} selected</p>
   200→          )}
   201→        </div>
   202→      )}
   203→
   204→      {/* SOURCE SELECTION */}
   205→      {type === "source_release" && isEditing && (
   206→        <>
   207→          <div className="space-y-2">
   208→            <Label>Project (to list sources)</Label>
   209→            <Select value={projectId} onValueChange={(v) => { setProjectId(v); setSourceId(""); }}>
   210→              <SelectTrigger><SelectValue placeholder="Select project" /></SelectTrigger>
   211→              <SelectContent>
   212→                {projectsData?.data.map((p) => (
   213→                  <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
   214→                ))}
   215→              </SelectContent>
   216→            </Select>
   217→          </div>
   218→          <div className="space-y-2">
   219→            <Label>Source</Label>
   220→            <Select value={sourceId} onValueChange={setSourceId} required>
   221→              <SelectTrigger><SelectValue placeholder="Select source" /></SelectTrigger>
   222→              <SelectContent>
   223→                {sourcesData?.data.map((s) => (
   224→                  <SelectItem key={s.id} value={s.id}>{s.provider}: {s.repository}</SelectItem>
   225→                ))}
   226→              </SelectContent>
   227→            </Select>
   228→          </div>
   229→        </>
   230→      )}
   231→      {type === "source_release" && !isEditing && (
   232→        <div className="space-y-2">
   233→          <div className="flex items-center justify-between">
   234→            <Label>Sources</Label>
   235→            {allSourceIds.length > 0 && (
   236→              <button
   237→                type="button"
   238→                onClick={toggleAllSources}
   239→                className="text-xs text-blue-600 hover:text-blue-800"
   240→              >
   241→                {selectedSourceIds.length === allSourceIds.length ? "Deselect all" : "Select all"}
   242→              </button>
   243→            )}
   244→          </div>
   245→          <div className="max-h-64 overflow-y-auto rounded-md border border-input p-2 space-y-3">
   246→            {sourcesByProject.map((group) => (
   247→              <div key={group.projectName}>
   248→                <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider px-2 pb-1">{group.projectName}</p>
   249→                <div className="space-y-1">
   250→                  {group.sources.map((s) => (
   251→                    <label key={s.id} className="flex items-center gap-2 rounded px-2 py-1.5 hover:bg-accent cursor-pointer">
   252→                      <Checkbox
   253→                        checked={selectedSourceIds.includes(s.id)}
   254→                        onCheckedChange={() => toggleSourceId(s.id)}
   255→                      />
   256→                      <span className="text-sm">{s.provider}: {s.repository}</span>
   257→                    </label>
   258→                  ))}
   259→                </div>
   260→              </div>
   261→            ))}
   262→            {sourcesByProject.length === 0 && (
   263→              <p className="text-sm text-muted-foreground px-2 py-1">No sources found</p>
   264→            )}
   265→          </div>
   266→          {selectedSourceIds.length > 0 && (
   267→            <p className="text-xs text-muted-foreground">{selectedSourceIds.length} selected</p>
   268→          )}
